@function difference($lists...)
  @if list.length($lists) < 2
    @error 'Must be at least 2 lists'
  $result: ()
  $common: intersection($lists...)
  @each $list in $lists
    @each $item in $list
      @if not contains($common, $item)
        $result: list.append($result, $item)
  @return $result

@function intersection($lists...)
  @if list.length($lists) < 2
    @error 'Must be at least 2 lists'
  $result: unique(first($lists))
  @each $list in tail($lists)
    $temp: -same-format-($result)
    @each $item in $result
      @if contains($list, $item)
        $temp: list.append($temp, $item)
    $result: $temp
  @return $result

@mixin position($position, $top: null, $right: null, $bottom: null, $left: null, $z: null)
  @if list.has-multiple($position)
    @include position($position...)
  @else if list.has-multiple($top)
    @include position($position, $top...)
  @else
    position: $position
    top: $top
    right: $right
    bottom: $bottom
    left: $left

    @if meta.is-number($z)
      z-index: $z

@mixin rectangle($width: null, $height: null, $radius: null, $background: null)
  @include size($width, $height)

  @if meta.is-list($background)
    background: list.join($background, [], auto, false)
  @else
    background: $background

  @if meta.is-list($radius)
    border-radius: list.join($radius, [], space, false)
  @else
    border-radius: $radius

@function every($list, $predicate, $args...)

	@if meta.type-of($predicate) != 'function'
		@error parameter-type.parameter-type('every', 'predicate', $predicate, 'function')

	$index: 1

	@each $item in $list

		@if not meta.call($predicate, $item, $index, $list, $args...)
			@return false

		$index: $index + 1

	@return true

=stretch($offset-top: 0, $offset-right: 0, $offset-bottom: 0, $offset-left: 0)
  position: absolute
  @if $offset-top
    top: $offset-top
  @if $offset-bottom
    bottom: $offset-bottom
  @if $offset-left
    left: $offset-left
  @if $offset-right
    right: $offset-right

@function flat($list, $depth: 1, $separator: auto, $bracketed: auto)

	@if meta.type-of($depth) != 'number'
		@error parameter-type.parameter-type('flat', 'depth', $depth, 'number')

	@if $depth < 1
		@error parameter.parameter('The depth may not be less than 1', 'flat', 'depth')

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('flat')

	@return _flat($list, $depth, 1, $separator, $bracketed)

@function insert-nth($list, $index, $value, $separator: auto)
	$index: validate-index.validate-index('insert-nth', 'index', $index, $list)

	@if meta.type-of($index) != 'number'
		@error $index

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('insert-nth')

	@return insert-nth.insert-nth($list, $index, $value, $separator)

@function remove($list, $value, $separator: auto)

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('remove')

	$index: list.index($list, $value)

	@while $index
		$list: remove-nth.remove-nth($list, $index, $separator)
		$index: list.index($list, $value)

	@return $list

@function breakpoint-min($name, $breakpoints)
  $min: map.get($breakpoints, $name)
  @if $min != 0
    @return $min
  @else
    @return null

@function breakpoint-infix($name, $breakpoints)
  @if breakpoint-min($name, $breakpoints) == null
    @return ''
  @else
    @return '-#{$name}'

=span-grid($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter)
  float: left
  width: grid-span($span, $location, $columns, $gutter)
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
    @debug $grid-counter

@mixin ceaser-transition($properties: all, $duration: 500ms, $type: $ease, $delay: 0ms)
  @if $ceaser-legacy
    $easingValue : returnEaseType($type)
    @include transition($properties $duration cubic-bezier(unquote($easingValue)) $delay)
  @else
    @include transition($properties $duration cubic-bezier(unquote($type)) $delay)

@function flatten($list, $depth: null)
  $result: -same-format-($list)
  @each $item in $list
    // In case the item is the list and the depth is allowed.
    @if (has-multiple($item) and ($depth == null or $depth > 0))
      // Recursive unpack of items with defined depth level.
      $nFlatten: flatten($item, if($depth, $depth - 1, $depth))
      @each $nItem in $nFlatten
        $result: list.append($result, $nItem)
    @else
      $result: list.append($result, $item)
  @return $result

@mixin -flexbox-($display, $direction: null, $main: null, $cross: null, $wrap: null, $content: null)
  @if list.has-multiple($direction)
    @include -flexbox-($display, $direction...)
  @else
    display: $display
    flex-direction: $direction
    justify-content: $main
    align-items: $cross
    flex-wrap: $wrap
    align-content: $content

@mixin media($conditions...)
  @if list.is-empty($conditions)
    @content
  @else
    $raw-data: list.first($conditions)
    // Create media condition based on raw data.
    $condition: string.unquote(-create-condition-($raw-data))
    // Native media `at-rule` with media condition.
    @media #{$condition}
      $other: list.slice($conditions, 2)
      // Nested native media with other conditions.
      @include media($other...)
        @content

@function span($span, $location: 1, $columns: $columns)
  // zero out initial sum
  $sum: 0
  // from start point to end point
  @for $i from $location to ($location + $span)
    $sum: $sum + list-column-width($i, $columns)
  @return percentage($sum)

@function -same-format-($list)
  // Inherit the list separator.
  $separator: list.separator($list)
  // Determine whether list has brackets.
  $bracketed: list.is-bracketed($list)
  // Create the new list in proper format.
  @return list.join([], [], $separator, $bracketed)

@function -get-var-($name, $setFunction)
  // In case cache do not have var need to create it
  @if (not map.has-key($-cache-, $name))
    // Set variable under global internal cache
    $-cache-: map.set($-cache-, $name, meta.call($setFunction)) !global
  @return map.get($-cache-, $name)

@function set-order($config, $base: 0)
  $-is-ready: true !global

  // Convert in case config is list or string.
  @if meta.is-list($config) or meta.is-string($config)
    $config: -to-config-($config, $base)

  // Merge $config with already existing configs.
  $order: map.merge($order, $config) !global
  @return null

=background-clip($clip: $default-background-clip)
  // webkit and mozilla use the deprecated short [border | padding]
  $clip: unquote($clip)
  $deprecated: $clip
  @if $clip == padding-box
    $deprecated: padding
  @if $clip == border-box
    $deprecated: border
  // Support for webkit and mozilla's use of the deprecated short form
  +experimental(background-clip, $deprecated, -moz, -webkit, not -o, not -ms, not -khtml, not official)
  +experimental(background-clip, $clip, not -moz, not -webkit, not -o, not -ms, -khtml, official)
